#include<bits/stdc++.h>
using namespace std;
typedef long long i64;

i64 H(int n)
{
	i64 res = 0;
    int l = 1, r;
    while(l <= n)
    {
        r = n / (n / l);
        res += 1ll * (r - l + 1) * (n / l);
        l = r + 1;
    }
    return res;
}

int main()
{
	int t;
	cin >> t;
	for(int i = 1; i <= t; i++)
    {
        int n;
		cin >> n; 
        cout << H(n) << endl;
    }
	return 0;
}
